import{_ as e,o,c as a,ag as r}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"Qué Vendes — Servicios","description":"Agrega y administra los servicios que ofrece tu negocio","frontmatter":{"title":"Qué Vendes — Servicios","description":"Agrega y administra los servicios que ofrece tu negocio"},"headers":[],"relativePath":"studio/seccion-servicios.md","filePath":"studio/seccion-servicios.md"}'),i={name:"studio/seccion-servicios.md"};function s(n,t,d,l,c,u){return o(),a("div",null,[...t[0]||(t[0]=[r('<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>La sección de <strong>Servicios</strong> dentro del tab <strong>Qué Vendes</strong> es donde agregas y administras los servicios que tu negocio ofrece. Cada servicio se muestra como una tarjeta con ícono o imagen, nombre, descripción y un enlace de contacto.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p><strong>Tu panel → Qué Vendes</strong> (segundo ícono en el menú lateral, 🛒) → Sección <strong>Servicios</strong> (debajo de la sección de productos)</p><p>Verás tarjetas de servicios existentes y un botón <strong>&quot;Agregar Servicio&quot;</strong>.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><h3 id="lista-de-servicios" tabindex="-1">Lista de servicios <a class="header-anchor" href="#lista-de-servicios" aria-label="Permalink to &quot;Lista de servicios&quot;">​</a></h3><ul><li>Grid de tarjetas de servicios (3 columnas en escritorio)</li><li>Cada tarjeta muestra: ícono/imagen, nombre, descripción y link CTA</li><li>Al pasar el mouse: acciones <strong>Editar</strong> y <strong>Eliminar</strong></li></ul><h3 id="crear-editar-un-servicio" tabindex="-1">Crear / editar un servicio <a class="header-anchor" href="#crear-editar-un-servicio" aria-label="Permalink to &quot;Crear / editar un servicio&quot;">​</a></h3><p>Al darle clic a <strong>&quot;Agregar Servicio&quot;</strong> o <strong>Editar</strong>, se abre un modal:</p><table tabindex="0"><thead><tr><th>Campo</th><th>Obligatorio</th><th>Descripción</th></tr></thead><tbody><tr><td><strong>Nombre</strong></td><td>✅ Sí</td><td>Nombre del servicio</td></tr><tr><td><strong>Descripción</strong></td><td>No</td><td>Descripción corta del servicio</td></tr><tr><td><strong>Ícono</strong></td><td>No</td><td>Selector de ícono (alternativa a imagen)</td></tr><tr><td><strong>Imagen</strong></td><td>No</td><td>Foto del servicio (máx 2MB, WebP 800px)</td></tr><tr><td><strong>CTA Text</strong></td><td>No</td><td>Texto del botón de acción (ej: &quot;Solicitar cita&quot;)</td></tr><tr><td><strong>CTA Link</strong></td><td>No</td><td>Link del botón (generalmente WhatsApp)</td></tr><tr><td><strong>Activo</strong></td><td>—</td><td>Toggle para mostrar/ocultar en la landing</td></tr><tr><td><strong>Posición</strong></td><td>No</td><td>Orden de aparición</td></tr></tbody></table><h3 id="en-la-landing-lo-que-ve-tu-cliente" tabindex="-1">En la landing (lo que ve tu cliente) <a class="header-anchor" href="#en-la-landing-lo-que-ve-tu-cliente" aria-label="Permalink to &quot;En la landing (lo que ve tu cliente)&quot;">​</a></h3><p>Los servicios se muestran en tarjetas con dos variantes de diseño:</p><ul><li><strong>Cards</strong> — Tarjetas estándar con ícono arriba y texto debajo</li><li><strong>Spotlight</strong> — Diseño alternativo con más énfasis visual</li></ul><p>Se muestran los primeros 3 servicios con botón <strong>&quot;Ver más&quot;</strong> para cargar más (3→6→9).</p><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li>No permite agregar precios a los servicios — para precios usa Productos</li><li>No tiene agendamiento ni reservas — el cliente te contacta por WhatsApp</li><li>No tiene categorías de servicios</li><li>No tiene formulario de solicitud integrado</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Oportunidad</th><th>Crecimiento</th><th>Visión</th></tr></thead><tbody><tr><td>Máximo de servicios</td><td>3</td><td>6</td><td>9</td></tr><tr><td>Ícono o imagen</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>CTA personalizable</td><td>✅</td><td>✅</td><td>✅</td></tr><tr><td>Variante Spotlight</td><td>✅</td><td>✅</td><td>✅</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-consultora-estrategia-plus-en-valencia" tabindex="-1">Caso: Consultora &quot;Estrategia Plus&quot; en Valencia <a class="header-anchor" href="#caso-consultora-estrategia-plus-en-valencia" aria-label="Permalink to &quot;Caso: Consultora &quot;Estrategia Plus&quot; en Valencia&quot;">​</a></h3><p>Carlos ofrece servicios de consultoría. Va a <strong>Qué Vendes → Servicios</strong>:</p><ol><li><strong>&quot;Agregar Servicio&quot;</strong> → Nombre: &quot;Asesoría financiera&quot; → Descripción: &quot;Planificación y análisis de tu negocio&quot; → Ícono: 📊 → CTA: &quot;Agendar consulta&quot; → Guarda</li><li>Agrega: &quot;Consultoría legal&quot; → &quot;Contratos y constituciones de empresa&quot; → Ícono: ⚖️</li><li>Agrega: &quot;Coaching empresarial&quot; → &quot;Desarrollo de liderazgo&quot; → Ícono: 🎯</li></ol><p>Sus 3 servicios (límite del plan Oportunidad) aparecen en su landing como tarjetas visualmente atractivas. El botón &quot;Agendar consulta&quot; abre WhatsApp automáticamente.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/studio/productos-y-servicios.html">Productos y servicios</a> — Vista general del catálogo</li><li><a href="/studio/seccion-productos.html">Qué Vendes — Productos</a> — Cómo agregar productos</li><li><a href="/studio/seccion-visual.html">Visual — Variantes y efectos</a> — Cambiar entre Cards y Spotlight</li></ul>',26)])])}const p=e(i,[["render",s]]);export{h as __pageData,p as default};
